return-response.set-body:
@{
                            // Construct a custom JSON error response body
                            var error = context.LastError;
                            var json_error = new JObject(
                                new JProperty("errorSource", error?.Source),
                                new JProperty("errorMessage", error?.Message),
                                new JProperty("errorReason", error?.Reason)
                            );
                            string responseString = "{\"status\":\"ERROR\",\"errors\": [{\"code\": 1000900,\"message\": \"EIS-Unexpected Error: " + error?.Reason + " - " + error?.Message + "\"}]}";
                            return responseString;
                }
